const body = $json.body ?? $json;
const messageRaw = String(body.message ?? body.text ?? body.pergunta ?? '').trim();
return [{
  ...$json,
  body,
  usuario: body.usuario ?? body.user ?? 'administrativo',
  perfil: body.perfil ?? 'administrativo',
  messageRaw,
  message: messageRaw.toLowerCase(),
  arquivo: body.file ?? body.arquivo ?? null,
  receivedAt: new Date().toISOString()
}];

return [{
  ...$json,
  context: {
    projeto: 'JB Motos',
    tom: 'Profissional, direto, operacional e seguro',
    permissoes: {
      administrativo: ['produtos', 'fornecedores', 'estoque', 'financeiro', 'servicos'],
      mecanico: ['servicos', 'estoque_saida'],
      proprietario: ['todos']
    },
    regras: [
      'Nao misturar estado de produtos com estoque antes da integracao correta',
      'Importacao mista separa produtos e fornecedores',
      'Saida de estoque deve estar ligada a servico concluido',
      'Financeiro deve separar entradas, saidas e pagamentos de cliente'
    ],
    rotas: {
      produtos: '/admin/produtos',
      fornecedores: '/admin/cadastros/fornecedores',
      financeiro: '/admin/financeiro',
      servicos: '/admin/servicos',
      estoqueEntrada: '/admin/estoque/entrada',
      estoqueSaida: '/admin/estoque/saida',
      movimentacoes: '/admin/estoque/adicionar'
    }
  }
}];

const systemPrompt = `Voce e a IA administrativa da JB Motos. Classifique a solicitacao interna e devolva somente JSON valido.

Objetivo: dividir as demandas entre importacao, financeiro, servicos/mecanico, estoque, produtos/fornecedores e fallback.

Regras:
- Seja operacional e seguro.
- Nunca misture produto e estoque sem indicar validacao.
- Saida de estoque deve estar ligada a servico concluido.
- Importacao de planilha deve separar produtos e fornecedores.
- Financeiro pode orientar, mas deve respeitar permissao do usuario.

Formato obrigatorio:
{
  "intent": "boas_vindas|importacao_planilha|financeiro|servicos_mecanico|estoque|produtos_fornecedores|fallback",
  "confidence": 0.0,
  "replySuggestion": "texto curto",
  "entities": {
    "modulo": null,
    "arquivo": false,
    "periodo": null,
    "status": null
  },
  "nextStep": "acao recomendada",
  "riskLevel": "baixo|medio|alto"
}`;

return [{
  ...$json,
  aiRequest: {
    model: process.env.JB_MOTOS_IA_MODEL || 'gpt-4o-mini',
    temperature: 0.15,
    response_format: { type: 'json_object' },
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: JSON.stringify({ mensagem: $json.messageRaw, usuario: $json.usuario, perfil: $json.perfil, temArquivo: Boolean($json.arquivo), contexto: $json.context }) }
    ]
  }
}];

const apiUrl = process.env.JB_MOTOS_IA_API_URL;
const apiKey = process.env.JB_MOTOS_IA_API_KEY;

if (!apiUrl || !apiKey) {
  return [{
    ...$json,
    ai: {
      enabled: false,
      status: 'missing_config',
      message: 'Configure JB_MOTOS_IA_API_URL e JB_MOTOS_IA_API_KEY no ambiente do n8n.'
    }
  }];
}

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: apiUrl,
    headers: {
      Authorization: `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    },
    body: $json.aiRequest,
    json: true,
    timeout: 30000
  });

  const content = response?.choices?.[0]?.message?.content ?? response?.output_text ?? response?.reply ?? response;
  const decision = typeof content === 'string' ? JSON.parse(content) : content;

  return [{
    ...$json,
    ai: {
      enabled: true,
      status: 'ok',
      provider: 'external_api',
      decision
    }
  }];
} catch (error) {
  return [{
    ...$json,
    ai: {
      enabled: true,
      status: 'error',
      message: error.message
    }
  }];
}

const body = $json.body ?? $json;
const messageRaw = String(body.message ?? body.text ?? body.pergunta ?? '').trim();
const message = messageRaw.toLowerCase();
const usuario = body.usuario ?? body.user ?? 'administrativo';
const arquivo = body.file ?? body.arquivo ?? null;
const aiIntent = $json.ai?.decision?.intent ?? '';

const modulos = {
  importacao: {
    rota: '/admin/produtos',
    descricao: 'Importação de planilha mista para produtos e fornecedores'
  },
  financeiro: {
    rota: '/admin/financeiro',
    descricao: 'Apuração diária, entradas, saídas e pagamentos'
  },
  servicos: {
    rota: '/admin/servicos',
    descricao: 'Pedidos e serviços em andamento/concluídos'
  },
  estoqueEntrada: {
    rota: '/admin/estoque/entrada',
    descricao: 'Relatório de produtos que entraram no estoque'
  },
  estoqueSaida: {
    rota: '/admin/estoque/saida',
    descricao: 'Relatório de peças que saíram por serviço'
  },
  movimentacoes: {
    rota: '/admin/estoque/adicionar',
    descricao: 'Nova movimentação de estoque'
  }
};

function respostaBase(intent, reply, extra = {}) {
  return {
    ok: true,
    assistant: 'administrativo',
    usuario,
    intent,
    reply,
    actions: extra.actions ?? [],
    checklist: extra.checklist ?? [],
    data: { ...(extra.data ?? {}), ia: $json.ai ?? null },
    quickReplies: extra.quickReplies ?? [
      'Importar planilha',
      'Ver financeiro',
      'Serviços pendentes',
      'Movimentações de estoque'
    ]
  };
}

if (!message && !arquivo) {
  return [respostaBase('boas_vindas', 'Olá! Sou o assistente administrativo da JB Motos. Posso ajudar com importação de planilhas, financeiro, estoque, serviços pendentes e apoio ao mecânico.', {
    checklist: [
      'Importar planilha mista de produtos e fornecedores',
      'Abrir relatório financeiro',
      'Listar serviços pendentes para o mecânico',
      'Orientar entrada/saída de estoque'
    ]
  })];
}

if (aiIntent === 'importacao_planilha' || arquivo || message.includes('planilha') || message.includes('importar') || message.includes('arquivo')) {
  return [respostaBase('importacao_planilha', 'Certo. Vou orientar a importação da planilha mista. O sistema deve reconhecer automaticamente produtos e fornecedores e gravar cada um na lista correta.', {
    data: {
      arquivoRecebido: arquivo,
      colunasEsperadas: [
        'produto / nome produto / peça',
        'código produto / sku',
        'valor venda / preço venda',
        'quantidade / estoque',
        'fornecedor / empresa / razão social',
        'cnpj / contato / email / telefone'
      ]
    },
    checklist: [
      'Abrir módulo Produtos',
      'Acionar modal Importar',
      'Ler primeira aba da planilha',
      'Separar linhas de produto e fornecedor',
      'Evitar fornecedores duplicados por CNPJ, e-mail ou nome',
      'Confirmar total importado para o usuário'
    ],
    actions: [
      { type: 'navigate', payload: { route: modulos.importacao.rota } },
      { type: 'open_import_modal', payload: { module: 'produtos', accepts: ['csv', 'xls', 'xlsx'] } },
      { type: 'import_mixed_catalog_spreadsheet', payload: { targetProducts: true, targetSuppliers: true } }
    ]
  })];
}

if (aiIntent === 'financeiro' || message.includes('financeiro') || message.includes('entrada') || message.includes('saída') || message.includes('saida') || message.includes('lucro') || message.includes('pagamento')) {
  return [respostaBase('financeiro', 'Vou te ajudar na parte financeira. Posso abrir a apuração diária, conferir entradas e saídas, ou preparar um resumo para o proprietário.', {
    checklist: [
      'Conferir faturamento diário',
      'Conferir gasto real',
      'Calcular lucro apurado',
      'Separar pagamentos de cliente, entradas e saídas',
      'Gerar relatório PDF ou Excel quando solicitado'
    ],
    actions: [
      { type: 'navigate', payload: { route: modulos.financeiro.rota } },
      { type: 'load_financial_summary', payload: { period: $json.ai?.decision?.entities?.periodo ?? 'current' } }
    ]
  })];
}

if (aiIntent === 'servicos_mecanico' || message.includes('mecânico') || message.includes('mecanico') || message.includes('serviço') || message.includes('servico') || message.includes('pedido') || message.includes('pendente')) {
  return [respostaBase('servicos_mecanico', 'Vou auxiliar o mecânico com os pedidos e serviços pendentes. A ideia é mostrar horário, cliente, moto, serviço solicitado e peça provável para troca.', {
    data: {
      exemploServico: {
        horario: '15:30',
        cliente: 'Cliente do sistema',
        moto: 'Honda CG 160',
        servico: 'Troca de pastilha de freio',
        peca: 'Pastilha de Freio',
        status: 'pendente'
      }
    },
    checklist: [
      'Abrir módulo Serviços',
      'Filtrar serviços pendentes',
      'Mostrar ordem por horário',
      'Informar peça provável para o mecânico',
      'Após conclusão, orientar saída de estoque'
    ],
    actions: [
      { type: 'navigate', payload: { route: modulos.servicos.rota } },
      { type: 'filter_services', payload: { status: $json.ai?.decision?.entities?.status ?? 'pendente' } }
    ]
  })];
}

if (aiIntent === 'estoque' || message.includes('estoque') || message.includes('movimentação') || message.includes('movimentacao')) {
  return [respostaBase('estoque', 'Posso auxiliar na entrada, saída e movimentações de estoque. Entrada registra fornecedor e quantidade; saída deve ficar ligada ao serviço concluído.', {
    checklist: [
      'Entrada: fornecedor, produto, quantidade e motivo',
      'Saída: serviço concluído, peça usada, moto e responsável',
      'Movimentações: ajustes manuais e auditoria'
    ],
    actions: [
      { type: 'navigate', payload: { route: modulos.movimentacoes.rota } }
    ],
    quickReplies: ['Entrada de estoque', 'Saída por serviço', 'Histórico de movimentações']
  })];
}

if (aiIntent === 'produtos_fornecedores' || message.includes('produto') || message.includes('fornecedor')) {
  return [respostaBase('produtos_fornecedores', 'Posso ajudar a localizar, cadastrar, importar ou revisar produtos e fornecedores sem misturar os módulos.', {
    checklist: [
      'Produtos ficam no inventário administrativo',
      'Fornecedores ficam na lista de fornecedores',
      'A loja usa apenas os produtos marcados como visíveis na vitrine',
      'Importação mista separa cada tipo automaticamente'
    ],
    actions: [
      { type: 'navigate', payload: { route: modulos.importacao.rota } }
    ]
  })];
}

return [respostaBase('fallback', $json.ai?.decision?.replySuggestion || 'Posso ajudar com importação de planilha, produtos, fornecedores, financeiro, estoque ou serviços pendentes. Me diga qual área você quer abrir ou automatizar.', {
  quickReplies: ['Importar planilha', 'Financeiro', 'Serviços pendentes', 'Estoque']
})];

const risco = [];
if ($json.intent === 'importacao_planilha') risco.push('Validar colunas antes de gravar');
if ($json.intent === 'financeiro') risco.push('Nao expor dados sensiveis sem perfil autorizado');
return [{
  ...$json,
  audit: {
    workflow: 'Assistente.Administrativo',
    version: 'admin-profissional-v2',
    timestamp: new Date().toISOString(),
    usuario: $json.usuario,
    perfil: $json.perfil,
    intent: $json.intent,
    riscos: risco
  }
}];
